  const arr = [];
  for (let i = 0; i < str.length; i++) {
    const code = str.charCodeAt(i);
    if (code < 0x80) {
      arr.push(code);
    } else if (code < 0x800) {
      arr.push(0xc0 | (code >> 6));
      arr.push(0x80 | (code & 0x3f));
    } else if (code < 0xd800 || code >= 0xe000) {
      arr.push(0xe0 | (code >> 12));
      arr.push(0x80 | ((code >> 6) & 0x3f));
      arr.push(0x80 | (code & 0x3f));
    } else {
      // surrogate pair
      i++;
      const nextCode = str.charCodeAt(i);
      const fullCode = 0x10000 + (((code & 0x3ff) << 10) | (nextCode & 0x3ff));
      arr.push(0xf0 | (fullCode >> 18));
      arr.push(0x80 | ((fullCode >> 12) & 0x3f));
      arr.push(0x80 | ((fullCode >> 6) & 0x3f));
      arr.push(0x80 | (fullCode & 0x3f));
    }
  }
  return new Uint8Array(arr);
}

