import os
import requests
import json

api_key = os.environ.get("HOOKDECK_API_KEY", "REDACTED")
run_id = os.environ.get("ZEALT_RUN_ID", "zr-dov2ghu")

headers = {
    "Authorization": f"Bearer {api_key}",
    "Content-Type": "application/json"
}

# 1. Create Transformation
transform_name = f"transform-js-{run_id}"
transform_code = """addHandler('transform', (request, context) => {
  let body = request.body;
  if (typeof body === 'string') {
    try {
      body = JSON.parse(body);
    } catch (e) {
      // ignore
    }
  }

  if (body && typeof body === 'object') {
    if ('customer_id' in body) {
      body.userId = body.customer_id;
      delete body.customer_id;
    }
  }

  request.body = body;

  if (!request.headers) {
    request.headers = {};
  }
  request.headers['x-custom-transformed'] = 'true';

  return request;
});"""

transform_payload = {
    "name": transform_name,
    "code": transform_code
}

print(f"Creating transformation {transform_name}...")
r = requests.post("https://api.hookdeck.com/transformations", json=transform_payload, headers=headers)
print(f"Status: {r.status_code}")
print(r.text)
transform_data = r.json()
transformation_id = transform_data["id"]
print(f"Transformation ID: {transformation_id}")

# 2. Get Source and Destination IDs
source_name = f"transform-source-{run_id}"
dest_name = f"transform-dest-{run_id}"

# Find source ID
r = requests.get("https://api.hookdeck.com/sources", headers=headers)
sources = r.json().get("models", [])
source_id = None
for s in sources:
    if s["name"] == source_name:
        source_id = s["id"]
        break

# Find dest ID
r = requests.get("https://api.hookdeck.com/destinations", headers=headers)
dests = r.json().get("models", [])
dest_id = None
for d in dests:
    if d["name"] == dest_name:
        dest_id = d["id"]
        break

print(f"Source ID: {source_id}")
print(f"Destination ID: {dest_id}")

if not source_id or not dest_id:
    raise Exception("Source or Destination not found!")

# 3. Create Connection
connection_name = f"transform-conn-{run_id}"
connection_payload = {
    "name": connection_name,
    "source_id": source_id,
    "destination_id": dest_id,
    "rules": [
        {
            "type": "transform",
            "transformation_id": transformation_id
        }
    ]
}

print(f"Creating connection {connection_name}...")
r = requests.post("https://api.hookdeck.com/connections", json=connection_payload, headers=headers)
print(f"Status: {r.status_code}")
print(json.dumps(r.json(), indent=2))

